8	/**
9	 * Subscribes to one or more named SSE channels and calls router.refresh()
10	 * whenever an "update" event arrives on any of them. Multiple rapid events
11	 * are coalesced into a single refresh. Drop this into any client component
12	 * that wraps content which should stay live without polling.
13	 *
14	 * @param channels - The pub/sub channel(s) to subscribe to.
15	 */
16	export function useAutoRefresh(channels: FootyChannel | FootyChannel[]): void {
17	    const router = useRouter();
18	    const key = Array.isArray(channels) ?
19	        [...channels].sort().join(',') :
20	        channels;
21	
22	    useEffect(() => {
23	        const list = key.split(',') as FootyChannel[];
24	        let pending = false;
25	
26	        const listener = () => {
27	            if (!pending) {
28	                pending = true;
29	                setTimeout(() => {
30	                    pending = false;
31	                    router.refresh();
32	                }, 0);
33	            }
34	        };
35	
36	        const sources = list.map(ch => {
37	            const es = new EventSource(`/api/events?channel=${ch}`);
38	            es.addEventListener('update', listener);
39	            return es;
40	        });
41	
42	        return () => sources.forEach(es => es.close());
43	    }, [key, router]);
44	}
